class RabbitMQConfig:
    """Configuration for RabbitMQ connection with secure authentication."""

    def __init__(
        self,
        host: str = None,
        port: int = None,
        username: str = None,
        password: str = None,
        virtual_host: str = None,
        use_ssl: bool = None,
        queue_name: str = None,
        exchange_name: str = None,
        routing_key: str = None,
        heartbeat: int = 600,
        connection_timeout: int = 30,
    ):
        # Load configuration from environment variables with secure defaults
        # Never hardcode credentials - always use environment variables or a secrets manager
        self.host = host or os.environ.get('RABBITMQ_HOST', 'localhost')
        self.port = port or int(os.environ.get('RABBITMQ_PORT', '5672'))
        self.username = username or os.environ.get('RABBITMQ_USERNAME')
        self.password = password or os.environ.get('RABBITMQ_PASSWORD')
        self.virtual_host = virtual_host or os.environ.get('RABBITMQ_VHOST', '/')
        self.use_ssl = use_ssl if use_ssl is not None else os.environ.get('RABBITMQ_USE_SSL', 'false').lower() == 'true'
        self.queue_name = queue_name or os.environ.get('RABBITMQ_QUEUE', 'task_queue')
        self.exchange_name = exchange_name or os.environ.get('RABBITMQ_EXCHANGE', 'task_exchange')
        self.routing_key = routing_key or os.environ.get('RABBITMQ_ROUTING_KEY', 'task')
        self.heartbeat = heartbeat
        self.connection_timeout = connection_timeout

        # Validate that credentials are provided
        if not self.username or not self.password:
            raise ValueError(
                "RabbitMQ credentials must be provided via environment variables "
                "RABBITMQ_USERNAME and RABBITMQ_PASSWORD, or passed explicitly. "
                "Never use default 'guest' credentials in production."
            )

    def get_connection_parameters(self) -> pika.ConnectionParameters:
        """Build secure connection parameters."""
        credentials = pika.PlainCredentials(
            username=self.username,
            password=self.password
        )

        ssl_options = None
        if self.use_ssl:
            ssl_context = ssl.create_default_context()
            # Load CA certificate if provided
            ca_cert = os.environ.get('RABBITMQ_CA_CERT')
            client_cert = os.environ.get('RABBITMQ_CLIENT_CERT')
            client_key = os.environ.get('RABBITMQ_CLIENT_KEY')

            if ca_cert:
                ssl_context.load_verify_locations(ca_cert)
            if client_cert and client_key:
                ssl_context.load_cert_chain(client_cert, client_key)

            ssl_context.check_hostname = True
            ssl_context.verify_mode = ssl.CERT_REQUIRED
            ssl_options = pika.SSLOptions(ssl_context, self.host)

        return pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            ssl_options=ssl_options,
            heartbeat=self.heartbeat,
            blocked_connection_timeout=self.connection_timeout,
        )


class RabbitMQConnection:
    """Manages RabbitMQ connection with automatic reconnection."""

    def __init__(self, config: RabbitMQConfig):
        self.config = config
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.channel.Channel] = None
        self._max_retries = 5
        self._retry_delay = 5

    def connect(self):
        """Establish connection to RabbitMQ with retry logic."""
        for attempt in range(1, self._max_retries + 1):
            try:
                logger.info(
                    f"Connecting to RabbitMQ at {self.config.host}:{self.config.port} "
                    f"(attempt {attempt}/{self._max_retries})"
                )
                params = self.config.get_connection_parameters()
                self.connection = pika.BlockingConnection(params)
                self.channel = self.connection.channel()

                # Enable publisher confirms for reliable publishing
                self.channel.confirm_delivery()

                logger.info("Successfully connected to RabbitMQ")
                return
            except pika.exceptions.AMQPConnectionError as e:
                logger.error(f"Connection attempt {attempt} failed: {e}")
                if attempt < self._max_retries:
                    logger.info(f"Retrying in {self._retry_delay} seconds...")
                    time.sleep(self._retry_delay)
                else:
                    raise ConnectionError(
                        f"Failed to connect to RabbitMQ after {self._max_retries} attempts"
                    ) from e

    def close(self):
        """Gracefully close the connection."""
        try:
            if self.channel and self.channel.is_open:
                self.channel.close()
            if self.connection and self.connection.is_open:
                self.connection.close()
            logger.info("RabbitMQ connection closed")
        except Exception as e:
            logger.error(f"Error closing connection: {e}")

    def ensure_connected(self):
        """Ensure the connection is active, reconnect if necessary."""
        if not self.connection or self.connection.is_closed:
            self.connect()
        if not self.channel or self.channel.is_closed:
            self.channel = self.connection.channel()
            self.channel.confirm_delivery()

    def __enter__(self):
        self.connect()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()
        return False


class TaskPublisher:
    """Publishes task messages to RabbitMQ with reliable delivery."""

    def __init__(self, config: RabbitMQConfig):
        self.config = config
        self.conn_manager = RabbitMQConnection(config)

    def setup(self):
        """Set up exchange and queue with proper bindings."""
        self.conn_manager.ensure_connected()
        channel = self.conn_manager.channel

        # Declare a durable exchange
        channel.exchange_declare(
            exchange=self.config.exchange_name,
            exchange_type='direct',
            durable=True,
        )

        # Declare a durable queue with dead-letter exchange for failed messages
        dlx_exchange = f"{self.config.exchange_name}.dlx"
        dlx_queue = f"{self.config.queue_name}.dlq"

        # Dead letter exchange and queue
        channel.exchange_declare(
            exchange=dlx_exchange,
            exchange_type='direct',
            durable=True,
        )
        channel.queue_declare(
            queue=dlx_queue,
            durable=True,
        )
        channel.queue_bind(
            queue=dlx_queue,
            exchange=dlx_exchange,
            routing_key=self.config.routing_key,
        )

        # Main task queue with dead-letter configuration
        channel.queue_declare(
            queue=self.config.queue_name,
            durable=True,
            arguments={
                'x-dead-letter-exchange': dlx_exchange,
                'x-dead-letter-routing-key': self.config.routing_key,
                'x-message-ttl': 86400000,  # 24 hours TTL
                'x-max-length': 100000,  # Max queue length
            },
        )

        # Bind queue to exchange
        channel.queue_bind(
            queue=self.config.queue_name,
            exchange=self.config.exchange_name,
            routing_key=self.config.routing_key,
        )

        logger.info(
            f"Exchange '{self.config.exchange_name}' and queue '{self.config.queue_name}' configured"
        )

    def publish_task(self, task_type: str, payload: dict, priority: int = 0) -> str:
        """
        Publish a task message to the queue.

        Args:
            task_type: Type/name of the task
            payload: Task data payload
            priority: Message priority (0-9)

        Returns:
            Task ID string
        """
        self.conn_manager.ensure_connected()

        task_id = f"{task_type}-{datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}"

        message = {
            'task_id': task_id,
            'task_type': task_type,
            'payload': payload,
            'created_at': datetime.utcnow().isoformat(),
            'retry_count': 0,
            'max_retries': 3,
        }

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent message
            content_type='application/json',
            message_id=task_id,
            timestamp=int(time.time()),
            priority=min(max(priority, 0), 9),
            headers={
                'task_type': task_type,
                'version': '1.0',
            },
        )

        try:
            self.conn_manager.channel.basic_publish(
                exchange=self.config.exchange_name,
                routing_key=self.config.routing_key,
                body=json.dumps(message),
                properties=properties,
                mandatory=True,  # Ensure message is routed to a queue
            )
            logger.info(f"Published task: {task_id} (type: {task_type})")
            return task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message {task_id} was not routed to any queue")
            raise
        except pika.exceptions.NackError:
            logger.error(f"Message {task_id} was nacked by the broker")
            raise

    def publish_batch(self, tasks: list) -> list:
        """
        Publish multiple tasks.

        Args:
            tasks: List of dicts with 'task_type', 'payload', and optional 'priority'

        Returns:
            List of task IDs
        """
        task_ids = []
        for task in tasks:
            task_id = self.publish_task(
                task_type=task['task_type'],
                payload=task['payload'],
                priority=task.get('priority', 0),
            )
            task_ids.append(task_id)
        return task_ids

    def close(self):
        """Close the publisher connection."""
        self.conn_manager.close()


class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ."""

    def __init__(self, config: RabbitMQConfig, prefetch_count: int = 1):
        self.config = config
        self.conn_manager = RabbitMQConnection(config)
        self.prefetch_count = prefetch_count
        self._task_handlers: dict = {}
        self._default_handler: Optional[Callable] = None
        self._running = False

    def register_handler(self, task_type: str, handler: Callable):
        """
        Register a handler function for a specific task type.

        Args:
            task_type: The task type string to handle
            handler: Callable that takes (task_id, payload) and returns bool
        """
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def set_default_handler(self, handler: Callable):
        """Set a default handler for unregistered task types."""
        self._default_handler = handler
        logger.info("Default task handler set")

    def _on_message(self, channel, method, properties, body):
        """Internal message callback with error handling and retry logic."""
        task_id = "unknown"
        try:
            message = json.loads(body)
            task_id = message.get('task_id', 'unknown')
            task_type = message.get('task_type', 'unknown')
            payload = message.get('payload', {})
            retry_count = message.get('retry_count', 0)
            max_retries = message.get('max_retries', 3)

            logger.info(
                f"Received task: {task_id} (type: {task_type}, retry: {retry_count})"
            )

            # Find appropriate handler
            handler = self._task_handlers.get(task_type, self._default_handler)

            if handler is None:
                logger.warning(
                    f"No handler registered for task type: {task_type}. Rejecting message."
                )
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Execute the handler
            success = handler(task_id, payload)

            if success:
                channel.basic_ack(delivery_tag=method.delivery_tag)
                logger.info(f"Task {task_id} completed successfully")
            else:
                # Handle failure with retry logic
                if retry_count < max_retries:
                    logger.warning(
                        f"Task {task_id} failed, requeueing (retry {retry_count + 1}/{max_retries})"
                    )
                    # Republish with incremented retry count
                    message['retry_count'] = retry_count + 1
                    retry_properties = pika.BasicProperties(
                        delivery_mode=2,
                        content_type='application/json',
                        message_id=task_id,
                        timestamp=int(time.time()),
                        headers={
                            'task_type': task_type,
                            'retry_count': retry_count + 1,
                        },
                    )
                    channel.basic_publish(
                        exchange=self.config.exchange_name,
                        routing_key=self.config.routing_key,
                        body=json.dumps(message),
                        properties=retry_properties,
                    )
                    channel.basic_ack(delivery_tag=method.delivery_tag)
                else:
                    logger.error(
                        f"Task {task_id} failed after {max_retries} retries. "
                        f"Sending to dead letter queue."
                    )
                    channel.basic_nack(
                        delivery_tag=method.delivery_tag, requeue=False
                    )

        except json.JSONDecodeError as e:
            logger.error(f"Invalid JSON message: {e}")
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
        except Exception as e:
            logger.error(f"Error processing task {task_id}: {e}", exc_info=True)
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start_consuming(self):
        """Start consuming messages from the queue."""
        self.conn_manager.connect()
        channel = self.conn_manager.channel

        # Set QoS - process one message at a time per consumer
        channel.basic_qos(prefetch_count=self.prefetch_count)

        # Ensure queue exists
        channel.queue_declare(
            queue=self.config.queue_name,
            durable=True,
            passive=True,  # Don't create, just check it exists
        )

        channel.basic_consume(
            queue=self.config.queue_name,
            on_message_callback=self._on_message,
            auto_ack=False,  # Manual acknowledgment for reliability
        )

        self._running = True
        logger.info(
            f"Consumer started. Waiting for tasks on queue '{self.config.queue_name}'..."
        )

        try:
            while self._running:
                try:
                    channel.start_consuming()
                except pika.exceptions.ConnectionClosedByBroker:
                    logger.warning("Connection closed by broker, reconnecting...")
                    self.conn_manager.connect()
                    channel = self.conn_manager.channel
                    channel.basic_qos(prefetch_count=self.prefetch_count)
                    channel.basic_consume(
                        queue=self.config.queue_name,
                        on_message_callback=self._on_message,
                        auto_ack=False,
                    )
                except pika.exceptions.StreamLostError:
                    logger.warning("Stream lost, reconnecting...")
                    time.sleep(2)
                    self.conn_manager.connect()
                    channel = self.conn_manager.channel
                    channel.basic_qos(prefetch_count=self.prefetch_count)
                    channel.basic_consume(
                        queue=self.config.queue_name,
                        on_message_callback=self._on_message,
                        auto_ack=False,
                    )
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self.stop()

    def stop(self):
        """Stop consuming and close connection."""
        self._running = False
        try:
            if self.conn_manager.channel and self.conn_manager.channel.is_open:
                self.conn_manager.channel.stop_consuming()
        except Exception:
            pass
        self.conn_manager.close()
        logger.info("Consumer stopped")


